import redis, time, logging
from contextlib import contextmanager

r = redis.Redis(host="localhost", port=6379, decode_responses=True)

@contextmanager
def distributed_lock(job_id: str, ttl_seconds: int = 3600):
    """Acquire a Redis lock; raise RuntimeError if already held.""""
    lock_key = f"cron_lock:{job_id}"
    acquired = r.set(lock_key, "locked", nx=True, ex=ttl_seconds)
    if not acquired:
        raise RuntimeError(f"Job {job_id} already running (lock held)")
    try:
        yield
    finally:
        r.delete(lock_key)

def daily_summary_agent():
    try:
        with distributed_lock("daily-summary", ttl_seconds=1800):
            logging.info("Lock acquired — starting daily summary")
            # ... agent logic here
            logging.info("Daily summary complete")
    except RuntimeError as e:
        logging.info(f"Skipping: {e}")  # Another worker is already running this job

