import time, logging
from anthropic import Anthropic

client = Anthropic()

def count_pending_items() -> int:
    # Simulated: query a database for unprocessed items
    import random
    return random.randint(0, 200)

def process_pending(count: int) -> None:
    if count == 0:
        return
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        messages=[{"role": "user", "content": f"Process {count} pending items (simulated)."}]
    )
    logging.info(f"Processed {count} items: {resp.content[0].text[:60]}")

def adaptive_loop(
    min_interval: int = 60,    # 1 minute minimum
    max_interval: int = 3600,  # 1 hour maximum
    high_threshold: int = 50,  # items above which we run more often
):
    interval = max_interval
    while True:
        pending = count_pending_items()
        process_pending(pending)

        # If there is a lot of work, check again soon; otherwise back off
        if pending >= high_threshold:
            interval = min_interval
        elif pending > 0:
            interval = min(interval * 2, max_interval)  # Exponential back-off
        else:
            interval = max_interval

        logging.info(f"Next run in {interval}s (pending: {pending})")
        time.sleep(interval)

